import React, { useState, useEffect } from "react";
import { createNote, updateNote, summarizeNote } from "../services/api";
import { X, Sparkles, Pin, PinOff, Tag, Loader } from "lucide-react";

const COLORS = ["default", "red", "orange", "yellow", "green", "blue", "purple"];
const COLOR_DOTS = {
  default: "#4a4959", red: "#f05e5e", orange: "#f5943b",
  yellow: "#f5c842", green: "#4fd68a", blue: "#4fb8f5", purple: "#7c6af7",
};

export default function NoteEditor({ note, onClose, onSaved, onToast }) {
  const isEdit = !!note?._id;
  const [form, setForm] = useState({
    title: note?.title || "",
    content: note?.content || "",
    color: note?.color || "default",
    isPinned: note?.isPinned || false,
    tags: note?.tags?.join(", ") || "",
  });
  const [summary, setSummary] = useState(note?.summary || "");
  const [saving, setSaving] = useState(false);
  const [summarizing, setSummarizing] = useState(false);
  const [error, setError] = useState("");

  // Close on Escape
  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setError("");
  };

  const handleSave = async () => {
    if (!form.title.trim()) { setError("Title is required."); return; }
    if (!form.content.trim()) { setError("Content is required."); return; }
    setSaving(true);
    try {
      const payload = {
        title: form.title,
        content: form.content,
        color: form.color,
        isPinned: form.isPinned,
        tags: form.tags ? form.tags.split(",").map((t) => t.trim()).filter(Boolean) : [],
      };
      const fn = isEdit ? () => updateNote(note._id, payload) : () => createNote(payload);
      const { data } = await fn();
      onSaved(data.note, isEdit ? "update" : "create");
      onToast(isEdit ? "Note updated." : "Note created!", "success");
      onClose();
    } catch (err) {
      setError(err.response?.data?.error || "Failed to save note.");
    } finally {
      setSaving(false);
    }
  };

  const handleSummarize = async () => {
    if (!isEdit) { onToast("Save the note first before summarizing.", "info"); return; }
    setSummarizing(true);
    try {
      const { data } = await summarizeNote(note._id);
      setSummary(data.summary);
      onToast("Summary generated!", "success");
    } catch (err) {
      onToast(err.response?.data?.error || "Summarization failed.", "error");
    } finally {
      setSummarizing(false);
    }
  };

  return (
    <div style={styles.overlay} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={styles.modal} className="fade-in">
        {/* Header */}
        <div style={styles.header}>
          <h2 style={styles.title}>{isEdit ? "Edit Note" : "New Note"}</h2>
          <div style={styles.headerActions}>
            <button
              className="btn btn-ghost btn-sm"
              onClick={() => setForm((f) => ({ ...f, isPinned: !f.isPinned }))}
              title={form.isPinned ? "Unpin" : "Pin"}
            >
              {form.isPinned ? <Pin size={15} color="var(--accent)" /> : <PinOff size={15} />}
              {form.isPinned ? "Pinned" : "Pin"}
            </button>
            <button className="btn btn-ghost btn-sm" onClick={onClose} style={{ padding: "6px 8px" }}>
              <X size={16} />
            </button>
          </div>
        </div>

        {/* Color Picker */}
        <div style={styles.colorRow}>
          {COLORS.map((c) => (
            <button
              key={c}
              onClick={() => setForm((f) => ({ ...f, color: c }))}
              style={{
                ...styles.colorDot,
                background: COLOR_DOTS[c],
                transform: form.color === c ? "scale(1.35)" : "scale(1)",
                boxShadow: form.color === c ? `0 0 8px ${COLOR_DOTS[c]}` : "none",
              }}
              title={c}
            />
          ))}
        </div>

        {/* Fields */}
        <div style={styles.body}>
          <input
            className="input"
            name="title"
            placeholder="Note title…"
            value={form.title}
            onChange={handleChange}
            style={{ fontFamily: "var(--font-display)", fontWeight: 600, fontSize: 17 }}
          />

          <textarea
            className="input"
            name="content"
            placeholder="Write your thoughts here…"
            value={form.content}
            onChange={handleChange}
            style={{ minHeight: 160 }}
          />

          {/* Tags */}
          <div style={styles.tagRow}>
            <Tag size={14} color="var(--text-dim)" />
            <input
              className="input"
              name="tags"
              placeholder="Tags (comma separated: work, ideas, todo)"
              value={form.tags}
              onChange={handleChange}
              style={{ padding: "8px 12px", fontSize: 13 }}
            />
          </div>

          {error && <div style={styles.error}>{error}</div>}

          {/* AI Summary */}
          {summary && (
            <div style={styles.summary}>
              <div style={styles.summaryHeader}>
                <Sparkles size={14} color="var(--accent)" />
                <span style={{ color: "var(--accent-light)", fontSize: 12, fontWeight: 600, letterSpacing: "0.05em", textTransform: "uppercase" }}>AI Summary</span>
              </div>
              <p style={{ color: "var(--text-muted)", fontSize: 14, lineHeight: 1.6 }}>{summary}</p>
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={styles.footer}>
          <button
            className="btn btn-ghost btn-sm"
            onClick={handleSummarize}
            disabled={summarizing || !isEdit}
            title={!isEdit ? "Save note first" : "Summarize with AI"}
          >
            {summarizing ? <Loader size={14} style={{ animation: "spin 0.7s linear infinite" }} /> : <Sparkles size={14} />}
            {summarizing ? "Summarizing…" : "AI Summarize"}
          </button>
          <div style={{ display: "flex", gap: 8 }}>
            <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
            <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
              {saving ? <><span className="spinner" style={{ width: 14, height: 14 }} /> Saving…</> : isEdit ? "Update Note" : "Save Note"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  overlay: { position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", backdropFilter: "blur(4px)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 20 },
  modal: { background: "var(--bg2)", border: "1px solid var(--border)", borderRadius: "var(--radius)", width: "100%", maxWidth: 580, maxHeight: "90vh", display: "flex", flexDirection: "column", overflow: "hidden" },
  header: { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "18px 20px", borderBottom: "1px solid var(--border)" },
  title: { fontFamily: "var(--font-display)", fontSize: 18, fontWeight: 700 },
  headerActions: { display: "flex", gap: 8, alignItems: "center" },
  colorRow: { display: "flex", gap: 10, padding: "12px 20px", borderBottom: "1px solid var(--border)" },
  colorDot: { width: 18, height: 18, borderRadius: "50%", border: "none", cursor: "pointer", transition: "transform 0.15s, box-shadow 0.15s" },
  body: { padding: 20, display: "flex", flexDirection: "column", gap: 12, overflowY: "auto", flex: 1 },
  tagRow: { display: "flex", alignItems: "center", gap: 8 },
  error: { background: "rgba(240,94,94,0.1)", border: "1px solid rgba(240,94,94,0.2)", color: "var(--red)", padding: "8px 12px", borderRadius: "var(--radius-sm)", fontSize: 13 },
  summary: { background: "rgba(124,106,247,0.08)", border: "1px solid rgba(124,106,247,0.2)", borderRadius: "var(--radius-sm)", padding: "12px 16px" },
  summaryHeader: { display: "flex", alignItems: "center", gap: 6, marginBottom: 8 },
  footer: { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "14px 20px", borderTop: "1px solid var(--border)" },
};
